/*
 * rfid_access.ino — RFID Access Control Logger (ESP32)
 *
 * Elements:
 *   1. MFRC522 RFID (VSPI SS=5, RST=4)            — card detection
 *   2. N-MOSFET door strike (GPIO 26, 5-s pulse)   — door release
 *   3. SSD1306 OLED (I²C 0x3C)                     — status display
 *   4. MicroSD (HSPI CS=15)                         — CSV access log
 *   5. OTA ArduinoOTA (disarmed only)               — firmware update
 *   6. ESP32 WiFi + MQTT                            — remote events
 */

#include <Wire.h>
#include <SPI.h>
#include <MFRC522.h>
#include <Adafruit_SSD1306.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoOTA.h>
#include <SD.h>
#include <EEPROM.h>
#include <time.h>

// --- Credentials ---
const char* SSID      = "HomeNet";
const char* WIFI_PASS = "changeme";
const char* MQTT_HOST = "192.168.1.10";

// --- Pins ---
#define RFID_SS    5
#define RFID_RST   4
#define STRIKE_PIN 26
#define SD_CS      15

// --- Authorised UIDs stored in EEPROM ---
// Format: EEPROM[0] = count; then count × 7 bytes (1 size byte + up to 6 UID bytes)
#define EEPROM_SIZE 256
#define UID_SIZE     7
#define MAX_CARDS   20
// Special admin UID (first stored card = admin)
#define ADMIN_SLOT   0

// --- Constants ---
#define STRIKE_MS  5000UL

// --- Objects ---
MFRC522          rfid(RFID_SS, RFID_RST);
Adafruit_SSD1306  oled(128, 64, &Wire, -1);
WiFiClient        wc;
PubSubClient      mqtt(wc);

bool     armed      = true;
String   last_uid   = "";
String   last_result = "IDLE";
char     ts_buf[32];

void get_ts() {
  time_t t = time(nullptr);
  strftime(ts_buf, sizeof(ts_buf), "%Y-%m-%dT%H:%M:%SZ", gmtime(&t));
}

bool uid_authorised(MFRC522::Uid& uid) {
  uint8_t count = EEPROM.read(0);
  for (uint8_t i = 0; i < count && i < MAX_CARDS; i++) {
    uint8_t base = 1 + i * UID_SIZE;
    uint8_t sz   = EEPROM.read(base);
    if (sz != uid.size) continue;
    bool match = true;
    for (uint8_t b = 0; b < sz; b++)
      if (EEPROM.read(base + 1 + b) != uid.uidByte[b]) { match = false; break; }
    if (match) return true;
  }
  return false;
}

bool uid_is_admin(MFRC522::Uid& uid) {
  uint8_t count = EEPROM.read(0);
  if (count == 0) return false;
  uint8_t sz = EEPROM.read(1);
  if (sz != uid.size) return false;
  for (uint8_t b = 0; b < sz; b++)
    if (EEPROM.read(2 + b) != uid.uidByte[b]) return false;
  return true;
}

String uid_to_hex(MFRC522::Uid& uid) {
  String s;
  for (uint8_t i = 0; i < uid.size; i++) {
    if (uid.uidByte[i] < 0x10) s += "0";
    s += String(uid.uidByte[i], HEX);
  }
  s.toUpperCase();
  return s;
}

void log_sd(const char* uid, const char* result) {
  if (!SD.begin(SD_CS)) return;
  File f = SD.open("/ACCESS.CSV", FILE_WRITE);
  if (f) { f.printf("%s,%s,%s\n", ts_buf, uid, result); f.close(); }
  SD.end();
}

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    if (mqtt.connect("RFIDAccess")) break;
    delay(3000);
  }
}

void update_oled() {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 0);
  oled.printf(armed ? "[ARMED]" : "[DISARMED]");
  oled.setCursor(0, 16);
  oled.print(last_uid.length() ? last_uid.c_str() : "---");
  oled.setCursor(0, 28);
  bool granted = (last_result == "GRANTED");
  if (!granted && last_result != "IDLE") {
    oled.fillRect(0, 26, 128, 12, SSD1306_WHITE);
    oled.setTextColor(SSD1306_BLACK);
  }
  oled.print(last_result.c_str());
  oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 44); oled.print(ts_buf);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  EEPROM.begin(EEPROM_SIZE);
  Wire.begin();
  SPI.begin();

  rfid.PCD_Init();
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(STRIKE_PIN, OUTPUT); digitalWrite(STRIKE_PIN, LOW);

  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(500);
  configTime(0, 0, "pool.ntp.org");

  mqtt.setServer(MQTT_HOST, 1883);
  mqtt_reconnect();

  ArduinoOTA.setPassword("factdb-ota");
  ArduinoOTA.begin();

  Serial.println(F("RFID access system ready."));
}

void loop() {
  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();
  if (!armed) ArduinoOTA.handle();  // OTA only when disarmed

  if (!rfid.PICC_IsNewCardPresent() || !rfid.PICC_ReadCardSerial()) {
    delay(50);
    return;
  }

  get_ts();
  String uid_hex = uid_to_hex(rfid.uid);
  last_uid = uid_hex;

  if (uid_is_admin(rfid.uid)) {
    armed = !armed;
    last_result = armed ? "ARMED" : "DISARMED";
    char buf[64];
    snprintf(buf, sizeof(buf), "{\"event\":\"%s\",\"ts\":\"%s\"}", last_result.c_str(), ts_buf);
    mqtt.publish("access/status", buf, true);
  } else if (uid_authorised(rfid.uid)) {
    last_result = "GRANTED";
    digitalWrite(STRIKE_PIN, HIGH);
    delay(STRIKE_MS);
    digitalWrite(STRIKE_PIN, LOW);
  } else {
    last_result = "DENIED";
  }

  log_sd(uid_hex.c_str(), last_result.c_str());

  char buf[128];
  snprintf(buf, sizeof(buf), "{\"uid\":\"%s\",\"result\":\"%s\",\"ts\":\"%s\"}",
           uid_hex.c_str(), last_result.c_str(), ts_buf);
  mqtt.publish("access/events", buf);

  update_oled();
  rfid.PICC_HaltA();
  rfid.PCD_StopCrypto1();
}
